module top_module(
    input wire clk,
    input wire reset,
    input wire in,
    output reg [7:0] count_out
);reg in_last;

always @(posedge clk, posedge reset) begin
    if (reset) begin
        count_out <= 0;
        in_last <= 0;
    end
    else begin
        if (in && !in_last) begin
            count_out <= count_out + 1;
        end
        in_last <= in;
    end
end

endmodule
